mapper.select:
SELECT 
FROM t_community_registration_application
WHERE applicant_account_id = #{applicantAccountId}
ORDER BY create_time DESC, application_id DESC
LIMIT #{limit}

SELECT 
FROM t_community_registration_application
WHERE status = #{status}
ORDER BY submitted_at NULLS LAST, application_id ASC
LIMIT #{limit}

SELECT EXISTS (
    SELECT 1
    FROM t_community_registration_application
    WHERE community_fingerprint = #{fingerprint}
      AND status IN ('DRAFT', 'SUBMITTED', 'RETURNED', 'APPROVED')

      AND application_id <> #{excludeApplicationId}

)

SELECT EXISTS (
    SELECT 1
    FROM t_tenant_community
    WHERE status = 'ACTIVE'
      AND (
          registration_fingerprint = #{fingerprint}
          OR (
              district_code = #{districtCode}
              AND LOWER(REGEXP_REPLACE(tenant_name, '[[:space:]]+', '', 'g'))
                  = LOWER(REGEXP_REPLACE(#{communityName}, '[[:space:]]+', '', 'g'))
              AND LOWER(REGEXP_REPLACE(COALESCE(address, ''), '[[:space:]]+', '', 'g'))
                  = LOWER(REGEXP_REPLACE(#{communityAddress}, '[[:space:]]+', '', 'g'))
          )
      )
)

