INSERT INTO t_community_registration_material (
    application_id, material_type, object_key, original_file_name, content_type,
    file_size, etag, sha256, uploaded_by_account_id, status, create_time
) VALUES (
    #{applicationId}, #{materialType}, #{objectKey}, #{originalFileName}, #{contentType},
    #{fileSize}, #{etag}, #{sha256}, #{uploadedByAccountId}, #{status}, #{createTime}
)

mapper.select:
SELECT material_id, application_id, material_type, object_key, original_file_name,
       content_type, file_size, etag, sha256, uploaded_by_account_id, status, create_time
FROM t_community_registration_material
WHERE application_id = #{applicationId}
  AND material_id = #{materialId}
  AND status = 'ACTIVE'

mapper.update:
UPDATE t_community_registration_material material
SET status = 'REMOVED', update_time = CURRENT_TIMESTAMP
WHERE material.application_id = #{applicationId}
  AND material.material_id = #{materialId}
  AND material.status = 'ACTIVE'
  AND EXISTS (
      SELECT 1
      FROM t_community_registration_application application
      WHERE application.application_id = material.application_id
        AND application.applicant_account_id = #{applicantAccountId}
        AND application.status IN ('DRAFT', 'RETURNED')
  )

