INSERT INTO t_community_registration_review (
    application_id, decision, review_mode, reviewer_account_id, reviewer_user_id,
    reviewer_dept_id, review_comment, fallback_reason, create_time
) VALUES (
    #{applicationId}, #{decision}, #{reviewMode}, #{reviewerAccountId}, #{reviewerUserId},
    #{reviewerDeptId}, #{reviewComment}, #{fallbackReason}, #{createTime}
)

INSERT INTO sys_dept (
    parent_id, ancestors, dept_name, dept_type, dept_category, tenant_id, order_num, status
) VALUES (
    #{parentId}, #{ancestors}, #{deptName}, #{deptType}, #{deptCategory},
    #{tenantId}, #{orderNum}, '0'
)

INSERT INTO t_community_onboarding_workspace (
    application_id, tenant_id, status, official_affiliation_status,
    space_ledger_status, property_roster_status, denominator_status, owner_access_qr_status,
    initialization_dept_id, committee_dept_id, applicant_work_user_id, created_by_user_id
) VALUES (
    #{applicationId}, #{tenantId}, 'FOUNDATION_PENDING', #{officialAffiliationStatus},
    'PENDING', 'PENDING', 'PENDING', 'DISABLED', #{initializationDeptId},
    #{committeeDeptId}, #{applicantWorkUserId}, #{createdByUserId}
)
